import { Component, OnInit, OnDestroy, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router, RouterModule } from '@angular/router';
import { interval, Subject as RxSubject, takeUntil } from 'rxjs';
import { CoursesService, StatsService, LiveSessionsService } from '../../services';
import { Course, PlatformStats, LiveSession, Subject } from '../../models';

@Component({
  selector: 'app-home',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.scss']
})
export class HomeComponent implements OnInit, OnDestroy {
  private router = inject(Router);
  private coursesService = inject(CoursesService);
  private statsService = inject(StatsService);
  private liveSessionsService = inject(LiveSessionsService);

  private destroy$ = new RxSubject<void>();

  featuredCourses: Course[] = [];
  stats: PlatformStats | null = null;
  upcomingSessions: LiveSession[] = [];
  currentSlideIndex = 0;

  subjects: Subject[] = [
    { id: '1', name: 'Mathématiques', icon: '📐', color: 'blue' },
    { id: '2', name: 'Physique-Chimie', icon: '⚗️', color: 'purple' },
    { id: '3', name: 'Français', icon: '📚', color: 'pink' },
    { id: '4', name: 'Arabe', icon: '📖', color: 'amber' },
    { id: '5', name: 'Sciences Naturelles', icon: '🌿', color: 'green' },
    { id: '6', name: 'Histoire-Géographie', icon: '🌍', color: 'orange' },
    { id: '7', name: 'Informatique', icon: '💻', color: 'cyan' },
    { id: '8', name: 'Anglais', icon: '🇬🇧', color: 'red' }
  ];

  ngOnInit() {
    this.loadData();
    this.startCarousel();
  }

  ngOnDestroy() {
    this.destroy$.next();
    this.destroy$.complete();
  }

  private loadData() {
    // Load featured courses
    this.coursesService.getCourses().pipe(takeUntil(this.destroy$)).subscribe({
      next: (courses) => {
        this.featuredCourses = courses.slice(0, 6);
      },
      error: (error) => console.error('Error loading courses:', error)
    });

    // Load platform stats
    this.statsService.getPlatformStats().pipe(takeUntil(this.destroy$)).subscribe({
      next: (stats) => {
        this.stats = stats;
      },
      error: (error) => console.error('Error loading stats:', error)
    });

    // Load upcoming live sessions
    this.liveSessionsService.getLiveSessions(true).pipe(takeUntil(this.destroy$)).subscribe({
      next: (sessions) => {
        this.upcomingSessions = sessions.slice(0, 3);
      },
      error: (error) => console.error('Error loading sessions:', error)
    });
  }

  private startCarousel() {
    interval(4000).pipe(takeUntil(this.destroy$)).subscribe(() => {
      if (this.featuredCourses.length > 0) {
        this.currentSlideIndex = (this.currentSlideIndex + 1) % this.featuredCourses.length;
      }
    });
  }

  goToSlide(index: number) {
    this.currentSlideIndex = index;
  }

  nextSlide() {
    if (this.featuredCourses.length > 0) {
      this.currentSlideIndex = (this.currentSlideIndex + 1) % this.featuredCourses.length;
    }
  }

  prevSlide() {
    if (this.featuredCourses.length > 0) {
      this.currentSlideIndex = (this.currentSlideIndex - 1 + this.featuredCourses.length) % this.featuredCourses.length;
    }
  }

  exploreCourses() {
    this.router.navigate(['/courses']);
  }

  joinForFree() {
    this.router.navigate(['/register']);
  }

  enrollInCourse(courseId: string) {
    // Implementation would depend on auth state
    this.router.navigate(['/courses', courseId]);
  }

  joinSession(sessionId: string) {
    // Implementation would depend on auth state
    console.log('Join session:', sessionId);
  }

  trackByCourseId(index: number, course: Course): string {
    return course.id;
  }
}
